        return ((customComponent && (jsxs("div", { "data-index": item.id, className: classNames(className, focusedItem === index && 'focused'), onClick: onSelectItem(item), children: [isSearch && isExtraSmallDevice && jsx(Icon, { iconName: Icons.Search }), customComponent] }, item.id.toString()))) ||
            null);
